#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "riscv.h"
#include "defs.h"
#include "sbi.h"

// 外部定义的_entry函数，用于启动其他处理器核（hart）
extern void _entry();

// 启动其他处理器核的函数声明
void start_harts();

// 静态变量，用于标识引导启动的处理器核
static volatile int boot_hart = -1;

// main函数在所有CPU的监督模式下执行
void main() {
    // 检查当前CPU是否为引导启动的处理器核
    if (boot_hart == -1) {
        // 初始化引导处理器核的ID
        boot_hart = cpuid();

        // 初始化控制台和打印功能
        consoleinit();
        printfinit();

        // 打印启动信息
        printf("\n");
        printf("xv6 kernel is booting\n");
        printf("boot hart: %d\n", cpuid());
        printf("\n");

        // 初始化内核各子系统
        kinit();         // 物理页分配器
        kvminit();       // 创建内核页表
        kvminithart();   // 启用分页
        procinit();      // 进程表
        trapinit();      // 中断向量
        trapinithart();  // 安装内核中断向量
        plicinit();      // 设置中断控制器
        plicinithart();  // 请求PLIC设备中断
        binit();         // 缓存缓冲区
        iinit();         // inode表
        fileinit();      // 文件表
        virtio_disk_init(); // 模拟硬盘
        userinit();      // 第一个用户进程

        // 同步所有处理器核
        __sync_synchronize();

        // 启动其他处理器核
        start_harts();
    } else {
        // 同步所有处理器核
        __sync_synchronize();

        // 打印处理器核启动信息
        printf("hart %d starting\n", cpuid());

        // 初始化当前处理器核的页表和中断向量
        kvminithart();    // 启用分页
        trapinithart();   // 安装内核中断向量
        plicinithart();   // 请求PLIC设备中断
    }

    // 设置下一次时钟中断
    set_next_trigger();

    // 调用调度器
    scheduler();
}

// 启动其他处理器核的函数
void start_harts() {
    // 遍历所有处理器核
    for (int i = 0; i < NCPU; ++i) {
        // 检查处理器核的状态是否为停止
        if (sbi_hart_get_status(i) == SBI_HSM_STATE_STOPPED) {
            // 启动处理器核并传递_entry函数地址
            sbi_hart_start(i, (uint64)_entry, 0);
        }
    }
}

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "riscv.h"
#include "defs.h"

// 释放物理内存的函数声明
void freerange(void *pa_start, void *pa_end);

// 内核结束地址
extern char end[]; // 内核结束地址后的第一个地址
                   // 由 kernel.ld 定义

// 可用内存块的数据结构
struct run {
  struct run *next;
};

// 内核内存管理器结构体
struct {
  struct spinlock lock;
  struct run *freelist; // 空闲内存块链表
} kmem;

// 内核初始化函数
void
kinit()
{
  initlock(&kmem.lock, "kmem"); // 初始化内核锁
  freerange(end, (void*)PHYSTOP); // 初始化内存空间
}

// 释放一定范围的内存空间
void
freerange(void *pa_start, void *pa_end)
{
  char *p;
  p = (char*)PGROUNDUP((uint64)pa_start); // 向上对齐地址
  for(; p + PGSIZE <= (char*)pa_end; p += PGSIZE)
    kfree(p); // 释放内存
}

// 释放一个物理内存页
void
kfree(void *pa)
{
  struct run *r;

  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < end || (uint64)pa >= PHYSTOP)
    panic("kfree");

  // 用垃圾数据填充，以捕获悬空引用
  memset(pa, 1, PGSIZE);

  r = (struct run*)pa;

  acquire(&kmem.lock); // 获取内核锁
  r->next = kmem.freelist; // 添加到空闲链表
  kmem.freelist = r;
  release(&kmem.lock); // 释放内核锁
}

// 分配一个物理内存页
void *
kalloc(void)
{
  struct run *r;

  acquire(&kmem.lock); // 获取内核锁
  r = kmem.freelist; // 获取第一个空闲内存块
  if(r)
    kmem.freelist = r->next; // 更新空闲内存块链表
  release(&kmem.lock); // 释放内核锁

  if(r)
    memset((char*)r, 5, PGSIZE); // 用垃圾数据填充
  return (void*)r;
}

