// 用户态异常处理入口点
void
usertrap(void)
{
  int which_dev = 0;

  if((r_sstatus() & SSTATUS_SPP) != 0)
    panic("usertrap: not from user mode"); // 用户态异常应该是从用户态发生的，如果不是，说明可能有问题

  w_stvec((uint64)kernelvec); // 将异常和中断处理转入内核态的 kernelvec 函数

  struct proc *p = myproc();

  p->trapframe->epc = r_sepc(); // 保存用户程序计数器的值到 trapframe 结构体中的 epc 字段

  if(r_scause() == 8){ // 如果是系统调用
    if(killed(p))
      exit(-1); // 如果进程被标记为结束，退出进程

    p->trapframe->epc += 4; // epc 指向 ecall 指令，我们需要返回到下一条指令
    intr_on(); // 开启中断处理

    syscall(); // 调用系统调用处理函数
  } else if((which_dev = devintr()) != 0){ // 如果是设备中断
    // 空操作
  } else {
    printf("usertrap(): unexpected scause %p pid=%d\n", r_scause(), p->pid);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
    setkilled(p); // 标记进程为结束状态
  }

  if(killed(p))
    exit(-1); // 如果进程被标记为结束，退出进程

  if(which_dev == 2)
    yield(); // 如果是时钟中断，放弃 CPU

  usertrapret(); // 返回用户态
}

// 返回用户态
void
usertrapret(void)
{
  struct proc *p = myproc();

  intr_off(); // 关闭中断处理

  // 设置异常处理相关寄存器，以便用户态能够正常运行
  uint64 trampoline_uservec = TRAMPOLINE + (uservec - trampoline);
  w_stvec(trampoline_uservec);

  p->trapframe->kernel_satp = r_satp();         // 内核页表
  p->trapframe->kernel_sp = p->kstack + PGSIZE; // 进程的内核栈
  p->trapframe->kernel_trap = (uint64)usertrap; // 内核态异常处理函数
  p->trapframe->kernel_hartid = r_tp();         // 获取 hartid

  // 设置异常处理相关寄存器，以便用户态能够正常运行
  unsigned long x = r_sstatus();
  x &= ~SSTATUS_SPP; // 将 SPP 置为 0，表示用户态
  x |= SSTATUS_SPIE; // 在用户态开启中断
  w_sstatus(x);

  w_sepc(p->trapframe->epc); // 设置异常程序计数器
  uint64 satp = MAKE_SATP(p->pagetable);
  uint64 trampoline_userret = TRAMPOLINE + (userret - trampoline);
  ((void (*)(uint64))trampoline_userret)(satp); // 跳转到 trampoline.S 中的 userret 函数
}

// 内核态异常处理
void 
kerneltrap()
{
  int which_dev = 0;
  uint64 sepc = r_sepc();
  uint64 sstatus = r_sstatus();
  uint64 scause = r_scause();

  if((sstatus & SSTATUS_SPP) == 0)
    panic("kerneltrap: not from supervisor mode"); // 内核态异常应该是从内核态发生的，如果不是，说明可能有问题
  if(intr_get() != 0)
    panic("kerneltrap: interrupts enabled"); // 如果中断处理已经开启，说明可能有问题

  if((which_dev = devintr()) == 0){
    printf("scause %p\n", scause);
    printf("sepc=%p stval=%p\n", r_sepc(), r_stval());
    panic("kerneltrap"); // 如果不是设备中断，打印一些调试信息，然后 panic
  }

  if(which_dev == 2 && myproc() != 0 && myproc()->state == RUNNING)
    yield(); // 如果是时钟中断，且进程正在运行，则放弃 CPU

  w_sepc(sepc); // 恢复异常处理相关寄存器的值
  w_sstatus(sstatus);
}

// 时钟中断处理函数
void
clockintr()
{
  acquire(&tickslock);
  ticks++; // 每次时钟中断，时钟滴答数加一
  wakeup(&ticks); // 唤醒正在等待时钟的进程
  release(&tickslock);
}

// 处理设备中断，如果是时钟中断，返回 2，其他设备中断返回 1，未识别的中断返回 0
int
devintr()
{
  uint64 scause = r_scause();

  if((scause & 0x8000000000000000L) &&
     (scause & 0xff) == 9){ // 如果是外部中断
    int irq = plic_claim(); // 从 PLIC 中获取


    if(irq == UART0_IRQ){
      uartintr();
    } else if(irq == VIRTIO0_IRQ){
      virtio_disk_intr();
    } else if(irq){
      printf("unexpected interrupt irq=%d\n", irq);
    }

    // the PLIC allows each device to raise at most one
    // interrupt at a time; tell the PLIC the device is
    // now allowed to interrupt again.
    if(irq)
      plic_complete(irq);

    return 1;
  } else if(scause == 0x8000000000000005L){
    // timer interrupt

    if(cpuid() == 0){
      clockintr();
    }

    // acknowledge the software interrupt by clearing
    // the STIP bit in sip.
    w_sip(r_sip() & ~(1<<5));
    set_next_trigger();

    return 2;
  } else {
    return 0;
  }
}

