static struct inode*
create(char *path, short type, short major, short minor)
{
  struct inode *ip, *dp;
  char name[DIRSIZ];
  int denr;
  uint fstclus;
  struct fat32_dirent de;

  if((dp = nameiparent(path, name)) == 0)
    return 0;

  ilock(dp);

  if((ip = dirlookup(dp, name, 0)) != 0){
    iunlockput(dp);
    ilock(ip);
    if(type == T_FILE && (ip->type == T_FILE || ip->type == T_DEVICE))
      return ip;
    iunlockput(ip);
    return 0;
  }

  memset(&de, 0, sizeof(de));
  fat_sncopyin(de.shortname, name);
  denr = fat_dir_alloc_entry(dp, &de);
  if(denr < 0){
    iunlockput(dp);
    return 0;
  }
  ip = iget(dp->dev, dp->fstclus, denr);
  if(ip == 0){
    iunlockput(dp);
    return 0;
  }

  ilock(ip);
  ip->type = type;
  ip->major = major;
  ip->minor = minor;
  iupdate(ip);

  if(type == T_DIR){  // Create . and .. entries.
    fstclus = fat_alloc_clus(ip->dev, 0);
    ip->fstclus = fstclus;
    iupdate(ip);
    memset(&de, 0, sizeof(de));
    de.attr = ATTR_DIRECTORY;
    de.shortname[0] = '.';
    de.fst_clus_hi = fstclus >> 16;
    de.fst_clus_lo = fstclus & 0xFFFF;
    fat_dir_alloc_entry(ip, &de);
    de.shortname[1] = '.';
    de.fst_clus_hi = dp->fstclus >> 16;
    de.fst_clus_lo = dp->fstclus & 0xFFFF;
    fat_dir_alloc_entry(ip, &de);
  }

  iunlockput(dp);

  return ip;

