// Read the super block.
static void
readsb(int dev, struct fat32_bpb *sb)
{
  struct buf *bp;

  bp = bread(dev, 0);
  sb->byts_per_sec = *(int16*)&bp->data[11];
  sb->sec_per_clus = *(int8*)&bp->data[13];
  sb->rsvd_sec_cnt = *(int16*)&bp->data[14];
  sb->num_fats = *(int8*)&bp->data[16];
  sb->tot_sec_32 = *(int32*)&bp->data[32];
  sb->fat_sz_32 = *(int32*)&bp->data[36];
  sb->ext_flags = *(int16*)&bp->data[40];
  sb->root_clus = *(int32*)&bp->data[44];
  memmove(sb->fil_sys_type, &bp->data[82], 8);
  sb->active_fat = sb->ext_flags&0x7;
  sb->no_mirroring = !!(sb->ext_flags&(1<<7));
  sb->clus_sz = sb->sec_per_clus * sb->byts_per_sec;
  sb->data_clus_off = (sb->rsvd_sec_cnt + sb->num_fats * sb->fat_sz_32) / sb->sec_per_clus - 2;
  brelse(bp);
}

