// Copy a modified in-memory inode to disk.
// Must be called after every change to an ip->xxx field
// that lives on disk.
// Caller must hold ip->lock.
void
iupdate(struct inode *ip)
{
  struct buf *bp;
  struct fat32_dirent *de;
  uint de_blk_nr = bmap(ip->dev, ip->dirfstclus, ip->direntnr*sizeof(struct fat32_dirent)/BSIZE);
  uint de_blk_off = ip->direntnr*sizeof(struct fat32_dirent)%BSIZE;

  bp = bread(ip->dev, de_blk_nr + fbpb.data_clus_off);
  de = (struct fat32_dirent*)(bp->data + de_blk_off);
  if(ip->type == T_DEVICE){
    de->attr = ATTR_X_DEVICE;
    de->fst_clus_hi = ip->major;
    de->fst_clus_lo = ip->minor;
