// the address of virtio mmio register r.
#define R(r) ((volatile uint32 *)(VIRTIO0 + (r)))

static struct disk {
  char pages[2 * PGSIZE];


  struct virtq_desc *desc;

  struct virtq_avail *avail;

  struct virtq_used *used;

  // our own book-keeping.
  char free[NUM];  // is a descriptor free?
  uint16 used_idx; // we've looked this far in used[2..NUM].

  struct {
    struct buf *b;
    char status;
    int idx1;	// first index of a chain
  } info[NUM];

  struct virtio_blk_req ops[NUM];

  struct spinlock vdisk_lock;

} __attribute__ ((aligned (PGSIZE))) disk;

void
virtio_disk_init(void)
{
  uint32 status = 0;

  initlock(&disk.vdisk_lock, "virtio_disk");

  status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
  *R(VIRTIO_MMIO_STATUS) = status;

  status |= VIRTIO_CONFIG_S_DRIVER;
  *R(VIRTIO_MMIO_STATUS) = status;

  // negotiate features
  uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
  features &= ~(1 << VIRTIO_BLK_F_RO);
  features &= ~(1 << VIRTIO_BLK_F_SCSI);
  features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
  features &= ~(1 << VIRTIO_BLK_F_MQ);
  features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
  features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
  features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
  *R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

  // tell device that feature negotiation is complete.
  status |= VIRTIO_CONFIG_S_FEATURES_OK;
  *R(VIRTIO_MMIO_STATUS) = status;

  // tell device we're completely ready.
  status |= VIRTIO_CONFIG_S_DRIVER_OK;
  *R(VIRTIO_MMIO_STATUS) = status;

  *R(VIRTIO_MMIO_GUEST_PAGE_SIZE) = PGSIZE;

  // initialize queue 0.
  *R(VIRTIO_MMIO_QUEUE_SEL) = 0;
  uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
  if(max == 0)
    panic("virtio disk has no queue 0");
  if(max < NUM)
    panic("virtio disk max queue too short");
  *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
  memset(disk.pages, 0, sizeof(disk.pages));
  *R(VIRTIO_MMIO_QUEUE_PFN) = ((uint64)disk.pages) >> PGSHIFT;

  // desc = pages -- num * virtq_desc
  // avail = pages + 0x40 -- 2 * uint16, then num * uint16
  // used = pages + 4096 -- 2 * uint16, then num * vRingUsedElem

  disk.desc = (struct virtq_desc *) disk.pages;
  disk.avail = (struct virtq_avail *)(disk.pages + NUM * sizeof(struct virtq_desc));
  disk.used = (struct virtq_used *) (disk.pages + PGSIZE);

  // all NUM descriptors start out unused.
  for(int i = 0; i < NUM; i++)
    disk.free[i] = 1;

  // plic.c and trap.c arrange for interrupts from VIRTIO0_IRQ.
}

// find a free descriptor, mark it non-free, return its index.
static int
alloc_desc()
{
  for(int i = 0; i < NUM; i++){
    if(disk.free[i]){
      disk.free[i] = 0;
      return i;
    }
  }
  return -1;
}

// mark a descriptor as free.
static void
free_desc(int i)
{
  if(i >= NUM)
    panic("free_desc 1");
  if(disk.free[i])
    panic("free_desc 2");
  disk.desc[i].addr = 0;
  disk.desc[i].len = 0;
  disk.desc[i].flags = 0;
  disk.desc[i].next = 0;
  disk.free[i] = 1;
  wakeup(&disk.free[0]);
}

// free a chain of descriptors.
static void
free_chain(int i)
{
  while(1){
    int flag = disk.desc[i].flags;
    int nxt = disk.desc[i].next;
    free_desc(i);
    if(flag & VRING_DESC_F_NEXT)
      i = nxt;
    else
      break;
  }
}

static int
alloc_descs(int * restrict idx, int n)
{
  for(int i = 0; i < n; i++) {
    idx[i] = alloc_desc();
    if(idx[i] < 0){
      for(int j = 0; j < i; j++)
        free_desc(idx[j]);
      return -1;
    }
  }
  return 0;
}

static int
virtio_disk_rw_multiple(struct buf * restrict bufs[], int nbuf, int write)
{
  int ndesc = nbuf + 2;
  if (ndesc > NUM)
    return -1;

  acquire(&disk.vdisk_lock);

  // the spec's Section 5.2 says that legacy block operations use
  // three descriptors: one for type/reserved/sector, one for the
  // data, one for a 1-byte status result.

  // allocate the three descriptors.
  int idx[NUM];
  while (1) {
    if (alloc_descs(idx, ndesc) == 0)
      break;
    if (write) {	// write don't wait
      release(&disk.vdisk_lock);
      return -1;
    }
    sleep(&disk.free[0], &disk.vdisk_lock);
  }

  // format the three descriptors.
  // qemu's virtio-blk.c reads them.

  struct virtio_blk_req *buf0 = &disk.ops[idx[0]];
  struct virtq_desc *desc;

  buf0->type = write ? VIRTIO_BLK_T_OUT :	// write the disk
            VIRTIO_BLK_T_IN;	// read the disk
  buf0->reserved = 0;
  buf0->sector = bufs[0]->blockno * (BSIZE / 512);

  // first
  desc = &disk.desc[idx[0]];
  desc->addr = (uint64) buf0;
  desc->len = sizeof(struct virtio_blk_req);
  desc->flags = VRING_DESC_F_NEXT;
  desc->next = idx[1];

  for (int i = 1; i <= nbuf; i++) {
    desc = &disk.desc[idx[i]];
    desc->addr = (uint64) bufs[i - 1]->data;
    desc->len = BSIZE;
    desc->flags = write ? 0 :				// device reads b->data
              VRING_DESC_F_WRITE;	// device writes b->data
    desc->flags |= VRING_DESC_F_NEXT;
    desc->next = idx[i + 1];
  }

  // last
  desc = &disk.desc[idx[ndesc - 1]];
  desc->addr = (uint64) &disk.info[idx[0]].status;
  desc->len = 1;
  desc->flags = VRING_DESC_F_WRITE;		// device writes the status
  desc->next = 0;

  /**
   * Record struct buf for virtio_disk_intr().
   * If we are committing a wirte, we are not going to wait here.
   * After the write is done, the interrupt handler will use idx1
   * to free the desc chain that we allocated. In other way, this
   * is also a hint that this is a write buf, the handler needs to
   * do something about it.
   */
  disk.info[idx[0]].idx1 = write ? idx[0] : -1;
  disk.info[idx[0]].status = 0xff;		// device writes 0 on success
  disk.info[idx[0]].b = bufs[0];

  // tell the device the first index in our chain of descriptors.
  disk.avail->ring[disk.avail->idx % NUM] = idx[0];

  __sync_synchronize();

  // tell the device another avail ring entry is available.
  disk.avail->idx += 1; // not % NUM ...

  __sync_synchronize();

  *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0; // value is queue number

  int res = 0;
  if (!write) {
    bufs[0]->disk = 1;
    // Wait for virtio_disk_intr() to say request has finished.
    while (bufs[0]->disk == 1) {
      // printf(__INFO("virtio_disk_rw")" sleep on %d\n", b->sectorno);
      sleep(bufs[0], &disk.vdisk_lock);
    }
    res = -(disk.info[idx[0]].status != 0);
    free_chain(idx[0]);
  }

  release(&disk.vdisk_lock);
  return res;
}

void
virtio_disk_rw(struct buf *b, int write)
{
  virtio_disk_rw_multiple(&b, 1, write);
}

void
virtio_disk_intr()
{
  acquire(&disk.vdisk_lock);

  // the device won't raise another interrupt until we tell it
  // we've seen this interrupt, which the following line does.
  // this may race with the device writing new entries to
  // the "used" ring, in which case we may process the new
  // completion entries in this interrupt, and have nothing to do
  // in the next interrupt, which is harmless.
  *R(VIRTIO_MMIO_INTERRUPT_ACK) = *R(VIRTIO_MMIO_INTERRUPT_STATUS) & 0x3;

  __sync_synchronize();

  // the device increments disk.used->idx when it
  // adds an entry to the used ring.

  while(disk.used_idx != disk.used->idx){
    __sync_synchronize();
    int id = disk.used->ring[disk.used_idx % NUM].id;
    disk.used_idx += 1;

    if (disk.info[id].status != 0)
    	panic("virtio_disk_intr status");

    struct buf *b = disk.info[id].b;
    // disk.info[id].b = 0;
    if (disk.info[id].idx1 < 0) {	// read interrupt
      b->disk = 0;   				// disk is done with buf
      wakeup(b);
    } else {						// write interrupt
      free_chain(disk.info[id].idx1);
    }
  }
  release(&disk.vdisk_lock);
}

//
// 用于 16550a UART 的低级驱动程序例程。
//

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "riscv.h"
#include "spinlock.h"
#include "proc.h"
#include "defs.h"

#define Reg(reg) ((volatile unsigned char *)(UART0 + reg))

#define RHR 0                 // 接收保持寄存器（用于输入字节）
#define THR 0                 // 发送保持寄存器（用于输出字节）
#define IER 1                 // 中断使能寄存器
#define IER_RX_ENABLE (1<<0)
#define IER_TX_ENABLE (1<<1)
#define FCR 2                 // FIFO 控制寄存器
#define FCR_FIFO_ENABLE (1<<0)
#define FCR_FIFO_CLEAR (3<<1) // 清除两个 FIFO 的内容
#define ISR 2                 // 中断状态寄存器
#define LCR 3                 // 线路控制寄存器
#define LCR_EIGHT_BITS (3<<0)
#define LCR_BAUD_LATCH (1<<7) // 特殊模式，用于设置波特率
#define LSR 5                 // 线路状态寄存器
#define LSR_RX_READY (1<<0)   // 输入等待从 RHR 中读取
#define LSR_TX_IDLE (1<<5)    // THR 可以接受另一个要发送的字符

#define ReadReg(reg) (*(Reg(reg)))
#define WriteReg(reg, v) (*(Reg(reg)) = (v))

// 发送输出缓冲区。
struct spinlock uart_tx_lock;
#define UART_TX_BUF_SIZE 32
char uart_tx_buf[UART_TX_BUF_SIZE];
uint64 uart_tx_w; // 写入 uart_tx_buf[uart_tx_w % UART_TX_BUF_SIZE] 的下一个位置
uint64 uart_tx_r; // 从 uart_tx_buf[uart_tx_r % UART_TX_BUF_SIZE] 中读取的下一个位置

extern volatile int panicked; // 自 printf.c 中

void uartstart();

void
uartinit(void)
{
  // 禁用中断。
  WriteReg(IER, 0x00);

  // 特殊模式，用于设置波特率。
  WriteReg(LCR, LCR_BAUD_LATCH);

  // 波特率为 38.4K 的 LSB。
  WriteReg(0, 0x03);

  // 波特率为 38.4K 的 MSB。
  WriteReg(1, 0x00);

  // 离开设置波特率模式，
  // 并将字长设置为 8 位，无奇偶校验。
  WriteReg(LCR, LCR_EIGHT_BITS);

  // 重置并启用 FIFO。
  WriteReg(FCR, FCR_FIFO_ENABLE | FCR_FIFO_CLEAR);

  // 启用发送和接收中断。
  WriteReg(IER, IER_TX_ENABLE | IER_RX_ENABLE);

  initlock(&uart_tx_lock, "uart");
}

void
uartputc(int c)
{
  acquire(&uart_tx_lock);

  if(panicked){
    for(;;)
      ;
  }
  while(uart_tx_w == uart_tx_r + UART_TX_BUF_SIZE){
    // 缓冲区已满。
    // 等待 uartstart() 在缓冲区中开辟空间。
    sleep(&uart_tx_r, &uart_tx_lock);
  }
  uart_tx_buf[uart_tx_w % UART_TX_BUF_SIZE] = c;
  uart_tx_w += 1;
  uartstart();
  release(&uart_tx_lock);
}


void
uartputc_sync(int c)
{
  push_off();

  if(panicked){
    for(;;)
      ;
  }

  // 等待 LSR 中的 Transmit Holding Empty 被设置。
  while((ReadReg(LSR) & LSR_TX_IDLE) == 0)
    ;
  WriteReg(THR, c);

  pop_off();
}

void
uartstart()
{
  while(1){
    if(uart_tx_w == uart_tx_r){
      // 发送缓冲区为空。
      return;
    }

    if((ReadReg(LSR) & LSR_TX_IDLE) == 0){
      return;
    }

    int c = uart_tx_buf[uart_tx_r % UART_TX_BUF_SIZE];
    uart_tx_r += 1;

    // 可能 uartputc() 正在等待缓冲区中的空间。
    wakeup(&uart_tx_r);

    WriteReg(THR, c);
  }
}

// 从 UART 中读取一个输入字符。
// 如果没有等待的字符则返回 -1。
int
uartgetc(void)
{
  if(ReadReg(LSR) & 0x01){
    // 输入数据准备就绪。
    return ReadReg(RHR);
  } else {
    return -1;
  }
}

void
uartintr(void)
{
  // 读取和处理传入的字符。
  while(1){
    int c = uartgetc();
    if(c == -1)
      break;
    consoleintr(c);
  }

  // 发送缓冲区中的字符。
  acquire(&uart_tx_lock);
  uartstart();
  release(&uart_tx_lock);
}

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "riscv.h"
#include "proc.h"
#include "defs.h"
void
initlock(struct spinlock *lk, char *name)
{
  lk->name = name;
  lk->locked = 0;
  lk->cpu = 0;
}
void
acquire(struct spinlock *lk)
{
  push_off(); 
  if(holding(lk))
    panic("acquire");

  while(__sync_lock_test_and_set(&lk->locked, 1) != 0)
    ;
  __sync_synchronize();

  lk->cpu = mycpu();
}
void
release(struct spinlock *lk)
{
  if(!holding(lk))
    panic("release");
  lk->cpu = 0;
  __sync_synchronize();
  __sync_lock_release(&lk->locked);
  pop_off();
}
int
holding(struct spinlock *lk)
{
  int r;
  r = (lk->locked && lk->cpu == mycpu());
  return r;
}
void
push_off(void)
{
  int old = intr_get();
  intr_off();
  if(mycpu()->noff == 0)
    mycpu()->intena = old;
  mycpu()->noff += 1;
}
void
pop_off(void)
{
  struct cpu *c = mycpu();
  if(intr_get())
    panic("pop_off - interruptible");
  if(c->noff < 1)
    panic("pop_off");
  c->noff -= 1;
  if(c->noff == 0 && c->intena)
    intr_on();
}

#include "types.h"
#include "riscv.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "proc.h"
#include "sleeplock.h"
void
initsleeplock(struct sleeplock *lk, char *name)
{
  initlock(&lk->lk, "sleep lock");
  lk->name = name;
  lk->locked = 0;
  lk->pid = 0;
}
void
acquiresleep(struct sleeplock *lk)
{
  acquire(&lk->lk);
  while (lk->locked) {
    sleep(lk, &lk->lk);
  }
  lk->locked = 1;
  lk->pid = myproc()->pid;
  release(&lk->lk);
}
void
releasesleep(struct sleeplock *lk)
{
  acquire(&lk->lk);
  lk->locked = 0;
  lk->pid = 0;
  wakeup(lk);
  release(&lk->lk);
}
int
holdingsleep(struct sleeplock *lk)
{
  int r;
  acquire(&lk->lk);
  r = lk->locked && (lk->pid == myproc()->pid);
  release(&lk->lk);
  return r;
}

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "riscv.h"
#include "defs.h"
void
plicinit(void)
{
  *(uint32*)(PLIC + UART0_IRQ*4) = 1;
  *(uint32*)(PLIC + VIRTIO0_IRQ*4) = 1;
}
void
plicinithart(void)
{
  int hart = cpuid(); 
  *(uint32*)PLIC_SENABLE(hart) = (1 << UART0_IRQ) | (1 << VIRTIO0_IRQ); 
  *(uint32*)PLIC_SPRIORITY(hart) = 0;
}
int
plic_claim(void)
{
  int hart = cpuid();
  int irq = *(uint32*)PLIC_SCLAIM(hart);
  return irq;
}
void
plic_complete(int irq)
{
  int hart = cpuid();
  *(uint32*)PLIC_SCLAIM(hart) = irq;
}

//
// 控制台输入输出，通过UART实现。
// 读取操作是逐行进行的。
// 实现了一些特殊输入字符：
//   回车 -- 结束一行
//   控制-h -- 退格
//   控制-u -- 删除整行
//   控制-d -- 文件结束
//   控制-p -- 打印进程列表
//

#include <stdarg.h>
#include "types.h"
#include "param.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "fs.h"
#include "file.h"
#include "memlayout.h"
#include "riscv.h"
#include "defs.h"
#include "proc.h"

#define BACKSPACE 0x100
#define C(x)  ((x) - '@')  // 控制字符转换

//
// 发送一个字符到UART。
// 由printf()调用，也用于回显输入字符，
// 但不从write()中调用。
//
void consputc(int c) {
  if(c == BACKSPACE) {
    // 如果用户输入了退格键，用空格覆盖
    uartputc_sync('\b'); uartputc_sync(' '); uartputc_sync('\b');
  } else {
    uartputc_sync(c);
  }
}

struct {
  struct spinlock lock;
  // 输入缓冲区
  #define INPUT_BUF_SIZE 128
  char buf[INPUT_BUF_SIZE];
  uint r;  // 读取索引
  uint w;  // 写入索引
  uint e;  // 编辑索引
} cons;

//
// 用户对控制台的写操作。
// user_src表示数据源地址是否在用户空间。
//
int consolewrite(int user_src, uint64 src, int n) {
  int i;

  for(i = 0; i < n; i++) {
    char c;
    if(either_copyin(&c, user_src, src + i, 1) == -1)
      break;
    uartputc(c);
  }

  return i;
}

//
// 用户对控制台的读操作。
// 将最多n个字符的输入行复制到dst。
// user_dst表示dst是否在用户空间。
//
int consoleread(int user_dst, uint64 dst, int n) {
  uint target = n;
  int c;
  char cbuf;

  acquire(&cons.lock);
  while(n > 0) {
    // 等待中断处理程序将输入放入cons.buf中
    while(cons.r == cons.w) {
      if(killed(myproc())) {
        release(&cons.lock);
        return -1;
      }
      sleep(&cons.r, &cons.lock);
    }

    c = cons.buf[cons.r++ % INPUT_BUF_SIZE];

    if(c == C('D')) {  // 文件结束符
      if(n < target) {
        // 保存^D以备下次使用，确保
        // 调用者获得一个0字节的结果。
        cons.r--;
      }
      break;
    }

    // 将输入字节复制到用户空间缓冲区。
    cbuf = c;
    if(either_copyout(user_dst, dst, &cbuf, 1) == -1)
      break;

    dst++;
    --n;

    if(c == '\n') {
      // 一整行已到达，返回用户级读操作
      break;
    }
  }
  release(&cons.lock);

  return target - n;
}

//
// 控制台输入中断处理程序。
// uartintr()为输入字符调用此函数。
// 进行删除/行处理，将字符添加到cons.buf，
// 如果一整行已到达，则唤醒consoleread()。
//
void consoleintr(int c) {
  acquire(&cons.lock);

  switch(c) {
  case C('P'):  // 打印进程列表
    procdump();
    break;
  case C('U'):  // 删除整行
    while(cons.e != cons.w && cons.buf[(cons.e - 1) % INPUT_BUF_SIZE] != '\n') {
      cons.e--;
      consputc(BACKSPACE);
    }
    break;
  case C('H'): // 退格键
  case '\x7f': // 删除键
    if(cons.e != cons.w) {
      cons.e--;
      consputc(BACKSPACE);
    }
    break;
  default:
    if(c != 0 && cons.e - cons.r < INPUT_BUF_SIZE) {
      c = (c == '\r') ? '\n' : c;

      // 回显给用户
      consputc(c);

      // 存储以供consoleread()消费
      cons.buf[cons.e++ % INPUT_BUF_SIZE] = c;

      if(c == '\n' || c == C('D') || cons.e - cons.r == INPUT_BUF_SIZE) {
        // 如果一整行（或文件结束）已到达，则唤醒consoleread()
        cons.w = cons.e;
        wakeup(&cons.r);
      }
    }
    break;
  }

  release(&cons.lock);
}

// 初始化控制台
void consoleinit(void) {
  initlock(&cons.lock, "cons");

  uartinit();

  // 将读写系统调用连接到consoleread和consolewrite
  devsw[CONSOLE].read = consoleread;
  devsw[CONSOLE].write = consolewrite;
}

