// 格式化文件名
char* fmtname(char *path) {
    static char buf[DIRSIZ+1];
    char *p;

    // 找到最后一个斜杠后的第一个字符
    for(p = path + strlen(path); p >= path && *p != '/'; p--)
        ;
    p++;

    // 返回空格填充的名字
    if(strlen(p) >= DIRSIZ)
        return p;
    memmove(buf, p, strlen(p));
    memset(buf + strlen(p), ' ', DIRSIZ - strlen(p));
    return buf;
}

// 检查字符串中是否包含指定字符
int contains(char *str, char ch) {
    for(int i = 0; str[i] != 0; ++i) {
        if(str[i] == ch)
            return 1;
    }
    return 0;
}

// 主函数
int main(void) {
    int pid, wpid, fd, r;
    struct linux_dirent64 *de;

    // 打开控制台
    if(open("console", O_RDWR) < 0) {
        mknod("console", CONSOLE, 0);
        open("console", O_RDWR);
    }
    dup(0);  // 标准输出
    dup(0);  // 标准错误

    printf("console ok\n");

    // 打开根目录
    if((fd = open("/", 0)) < 0) {
        printf("cannot open /\n");
        exit(-1);
    }

    // 读取目录项
    while((r = getdents64(fd, dents, 512)) != 0) {
        if(r < 0) {
            printf("getdents64 failed\n");
            exit(-1);
        }

        for(int i = 0; i < r; i += ((struct linux_dirent64 *)&dents[i])->d_reclen) {
            de = (struct linux_dirent64 *)&dents[i];
            // 忽略非普通文件和包含点的文件
            if(de->d_type != DT_REG || contains(de->d_name, '.'))
                continue;

            // 创建子进程执行文件
            if((pid = fork()) < 0) {
                printf("init: fork failed\n");
                exit(1);
            }
            if(pid == 0) {
                argv[0] = de->d_name;
                exec(de->d_name, argv);
                printf("init: exec %s failed\n", de->d_name);
                exit(1);
            }

            // 等待子进程结束
            while(1) {
                wpid = wait((int *)0);
                if(wpid == pid) {
                    // shell 退出，重新启动
                    break;
                } else if(wpid < 0) {
                    printf("init: wait returned an error\n");
                    exit(1);
                } else {
                    // 无父进程的进程退出，不做任何处理
                }
            }
        }
    }

    close(fd);
    return 0;
}

