// 字符串比较函数，比较两个字符串p和q的大小
int strcmp(const char *p, const char *q) {
  while (*p && *p == *q)
    p++, q++;
  return (uchar)*p - (uchar)*q;
}

// 计算字符串s的长度
uint strlen(const char *s) {
  uint n;
  for (n = 0; s[n]; n++);
  return n;
}

// 内存设置函数，将n个字节的dst设置为c
void* memset(void *dst, int c, uint n) {
  char *cdst = (char *)dst;
  for (uint i = 0; i < n; i++) {
    cdst[i] = c;
  }
  return dst;
}

// 查找字符c在字符串s中第一次出现的位置
char* strchr(const char *s, char c) {
  for (; *s; s++)
    if (*s == c)
      return (char*)s;
  return 0;
}

// 从标准输入读取最多max-1个字符到buf中，并以'\0'结尾
char* gets(char *buf, int max) {
  int i, cc;
  char c;

  for (i = 0; i + 1 < max; ) {
    cc = read(0, &c, 1);
    if (cc < 1)
      break;
    buf[i++] = c;
    if (c == '\n' || c == '\r')
      break;
  }
  buf[i] = '\0';
  return buf;
}

// 获取文件n的状态信息并存储在st中
int stat(const char *n, struct stat *st) {
  int fd = open(n, O_RDONLY);
  if (fd < 0)
    return -1;
  int r = fstat(fd, st);
  close(fd);
  return r;
}

// 将字符串s转换为整数
int atoi(const char *s) {
  int n = 0;
  while ('0' <= *s && *s <= '9')
    n = n * 10 + *s++ - '0';
  return n;
}

// 内存移动函数，将n个字节从vsrc移动到vdst
void* memmove(void *vdst, const void *vsrc, int n) {
  char *dst = vdst;
  const char *src = vsrc;

  if (src > dst) {
    while (n-- > 0)
      *dst++ = *src++;
  } else {
    dst += n;
    src += n;
    while (n-- > 0)
      *--dst = *--src;
  }
  return vdst;
}

// 内存比较函数，比较s1和s2的前n个字节
int memcmp(const void *s1, const void *s2, uint n) {
  const uchar *p1 = s1, *p2 = s2;
  while (n-- > 0) {
    if (*p1 != *p2) {
      return *p1 - *p2;
    }
    p1++;
    p2++;
  }
  return 0;
}

// 内存复制函数，将n个字节从src复制到dst
void* memcpy(void *dst, const void *src, uint n) {
  return memmove(dst, src, n);
}

