// 定义数字字符数组用于进制转换
static char digits[] = "0123456789ABCDEF";

// 将字符写入指定文件描述符
static void putc(int fd, char c) {
    write(fd, &c, 1);
}

// 打印整数，支持不同的进制和符号
static void printint(int fd, int xx, int base, int sgn) {
    char buf[16];
    int i, neg;
    uint x;

    // 处理负数情况
    neg = 0;
    if (sgn && xx < 0) {
        neg = 1;
        x = -xx;
    } else {
        x = xx;
    }

    // 将整数转换为字符串
    i = 0;
    do {
        buf[i++] = digits[x % base];
    } while ((x /= base) != 0);
    if (neg)
        buf[i++] = '-';

    // 逆序输出
    while (--i >= 0)
        putc(fd, buf[i]);
}

// 打印指针
static void printptr(int fd, uint64 x) {
    putc(fd, '0');
    putc(fd, 'x');
    for (int i = 0; i < (sizeof(uint64) * 2); i++, x <<= 4)
        putc(fd, digits[x >> (sizeof(uint64) * 8 - 4)]);
}

// 按格式打印到指定文件描述符，支持 %d, %x, %p, %s, %c, %%
void vprintf(int fd, const char *fmt, va_list ap) {
    char *s;
    int c, i, state;

    state = 0;
    for (i = 0; fmt[i]; i++) {
        c = fmt[i] & 0xff;
        if (state == 0) {
            if (c == '%') {
                state = '%';
            } else {
                putc(fd, c);
            }
        } else if (state == '%') {
            switch (c) {
                case 'd':
                    printint(fd, va_arg(ap, int), 10, 1);
                    break;
                case 'l':
                    printint(fd, va_arg(ap, uint64), 10, 0);
                    break;
                case 'x':
                    printint(fd, va_arg(ap, int), 16, 0);
                    break;
                case 'p':
                    printptr(fd, va_arg(ap, uint64));
                    break;
                case 's':
                    s = va_arg(ap, char*);
                    if (s == 0)
                        s = "(null)";
                    while (*s != 0) {
                        putc(fd, *s);
                        s++;
                    }
                    break;
                case 'c':
                    putc(fd, va_arg(ap, uint));
                    break;
                case '%':
                    putc(fd, c);
                    break;
                default:
                    // 未知的%序列，直接打印以引起注意
                    putc(fd, '%');
                    putc(fd, c);
                    break;
            }
            state = 0;
        }
    }
}

// 按格式打印到指定文件描述符
void fprintf(int fd, const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    vprintf(fd, fmt, ap);
    va_end(ap);
}

// 按格式打印到标准输出
void printf(const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    vprintf(1, fmt, ap);
    va_end(ap);
}

