// 内存分配器

typedef long Align;

// 头部信息联合体
union header {
  struct {
    union header *ptr;  // 指向下一个空闲块
    uint size;          // 当前块的大小
  } s;
  Align x;              // 强制块的对齐
};

typedef union header Header;

static Header base;       // 空闲链表的基础节点
static Header *freep;     // 指向空闲链表的指针

// 释放内存块
void free(void *ap) {
  Header *bp, *p;

  bp = (Header *)ap - 1; // 指向要释放的块的头部
  for(p = freep; !(bp > p && bp < p->s.ptr); p = p->s.ptr) {
    // bp不在当前p和p->s.ptr之间，继续查找
    if(p >= p->s.ptr && (bp > p || bp < p->s.ptr)) {
      // 处理环绕情况
      break;
    }
  }

  // 合并相邻的空闲块
  if(bp + bp->s.size == p->s.ptr) {
    bp->s.size += p->s.ptr->s.size;
    bp->s.ptr = p->s.ptr->s.ptr;
  } else {
    bp->s.ptr = p->s.ptr;
  }

  if(p + p->s.size == bp) {
    p->s.size += bp->s.size;
    p->s.ptr = bp->s.ptr;
  } else {
    p->s.ptr = bp;
  }

  freep = p;
}

// 从系统申请更多的内存
static Header* morecore(uint nu) {
  char *p;
  Header *hp;

  // 最小分配单位
  if(nu < 4096)
    nu = 4096;

  // 分配内存
  p = sbrk(nu * sizeof(Header));
  if(p == (char *)-1)
    return 0;

  hp = (Header *)p;
  hp->s.size = nu;
  free((void *)(hp + 1)); // 将新分配的内存块加入到空闲链表中
  return freep;
}

// 分配内存
void* malloc(uint nbytes) {
  Header *p, *prevp;
  uint nunits;

  // 计算所需的Header单元数
  nunits = (nbytes + sizeof(Header) - 1) / sizeof(Header) + 1;

  // 初始化空闲链表
  if((prevp = freep) == 0) {
    base.s.ptr = freep = prevp = &base;
    base.s.size = 0;
  }

  // 遍历空闲链表寻找合适的块
  for(p = prevp->s.ptr; ; prevp = p, p = p->s.ptr) {
    if(p->s.size >= nunits) {
      // 找到合适的块
      if(p->s.size == nunits) {
        prevp->s.ptr = p->s.ptr;
      } else {
        p->s.size -= nunits;
        p += p->s.size;
        p->s.size = nunits;
      }
      freep = prevp;
      return (void *)(p + 1);
    }
    if(p == freep) {
      // 未找到合适的块，申请更多内存
      if((p = morecore(nunits)) == 0)
        return 0;
    }
  }
}

