#define NINODES 200

// 磁盘布局：
// [ 启动块 | 超级块 | 日志 | inode 块 | 空闲位图 | 数据块 ]

int nbitmap = FSSIZE/(BSIZE*8) + 1;
int ninodeblocks = NINODES / IPB + 1;
int nlog = LOGSIZE;
int nmeta;    // 元数据块数 (启动块, 超级块, 日志块, inode 块, 位图块)
int nblocks;  // 数据块数

int fsfd;
struct superblock sb;
char zeroes[BSIZE];
uint freeinode = 1;
uint freeblock;

void balloc(int);
void wsect(uint, void*);
void winode(uint, struct dinode*);
void rinode(uint inum, struct dinode *ip);
void rsect(uint sec, void *buf);
uint ialloc(ushort type);
void iappend(uint inum, void *p, int n);
void die(const char *);

// 转换为 riscv 字节序
ushort xshort(ushort x) {
    ushort y;
    uchar *a = (uchar*)&y;
    a[0] = x;
    a[1] = x >> 8;
    return y;
}

uint xint(uint x) {
    uint y;
    uchar *a = (uchar*)&y;
    a[0] = x;
    a[1] = x >> 8;
    a[2] = x >> 16;
    a[3] = x >> 24;
    return y;
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "Usage: mkfs fs.img files...\n");
        exit(1);
    }

    // 确保整数和结构体大小符合预期
    static_assert(sizeof(int) == 4, "Integers must be 4 bytes!");
    assert((BSIZE % sizeof(struct dinode)) == 0);
    assert((BSIZE % sizeof(struct dirent)) == 0);

    fsfd = open(argv[1], O_RDWR|O_CREAT|O_TRUNC, 0666);
    if (fsfd < 0) die(argv[1]);

    nmeta = 2 + nlog + ninodeblocks + nbitmap;
    nblocks = FSSIZE - nmeta;

    sb.magic = FSMAGIC;
    sb.size = xint(FSSIZE);
    sb.nblocks = xint(nblocks);
    sb.ninodes = xint(NINODES);
    sb.nlog = xint(nlog);
    sb.logstart = xint(2);
    sb.inodestart = xint(2+nlog);
    sb.bmapstart = xint(2+nlog+ninodeblocks);

    printf("nmeta %d (boot, super, log blocks %u inode blocks %u, bitmap blocks %u) blocks %d total %d\n",
           nmeta, nlog, ninodeblocks, nbitmap, nblocks, FSSIZE);

    freeblock = nmeta; // 第一个可分配的空闲块

    // 初始化文件系统
    for (int i = 0; i < FSSIZE; i++)
        wsect(i, zeroes);

    char buf[BSIZE] = {0};
    memmove(buf, &sb, sizeof(sb));
    wsect(1, buf);

    uint rootino = ialloc(T_DIR);
    assert(rootino == ROOTINO);

    // 创建根目录
    struct dirent de = { .inum = xshort(rootino) };
    strcpy(de.name, ".");
    iappend(rootino, &de, sizeof(de));

    de.inum = xshort(rootino);
    strcpy(de.name, "..");
    iappend(rootino, &de, sizeof(de));

    for (int i = 2; i < argc; i++) {
        char *shortname = strrchr(argv[i], '/');
        if (!shortname) shortname = argv[i];
        else shortname += 1;

        int fd = open(argv[i], 0);
        if (fd < 0) {
            if (errno == EISDIR) continue;
            die(argv[i]);
        }

        if (shortname[0] == '_') shortname += 1;

        uint inum = ialloc(T_FILE);

        de.inum = xshort(inum);
        strncpy(de.name, shortname, DIRSIZ);
        iappend(rootino, &de, sizeof(de));

        while (int cc = read(fd, buf, sizeof(buf))) {
            if (cc < 0) die("read");
            iappend(inum, buf, cc);
        }
        close(fd);
    }

    struct dinode din;
    rinode(rootino, &din);
    uint off = xint(din.size);
    off = ((off/BSIZE) + 1) * BSIZE;
    din.size = xint(off);
    winode(rootino, &din);

    balloc(freeblock);

    exit(0);
}

void wsect(uint sec, void *buf) {
    if (lseek(fsfd, sec * BSIZE, 0) != sec * BSIZE) die("lseek");
    if (write(fsfd, buf, BSIZE) != BSIZE) die("write");
}

void winode(uint inum, struct dinode *ip) {
    char buf[BSIZE];
    uint bn = IBLOCK(inum, sb);
    rsect(bn, buf);
    struct dinode *dip = ((struct dinode*)buf) + (inum % IPB);
    *dip = *ip;
    wsect(bn, buf);
}

void rinode(uint inum, struct dinode *ip) {
    char buf[BSIZE];
    uint bn = IBLOCK(inum, sb);
    rsect(bn, buf);
    struct dinode *dip = ((struct dinode*)buf) + (inum % IPB);
    *ip = *dip;
}

void rsect(uint sec, void *buf) {
    if (lseek(fsfd, sec * BSIZE, 0) != sec * BSIZE) die("lseek");
    if (read(fsfd, buf, BSIZE) != BSIZE) die("read");
}

uint ialloc(ushort type) {
    uint inum = freeinode++;
    struct dinode din = { .type = xshort(type), .nlink = xshort(1), .size = xint(0) };
    winode(inum, &din);
    return inum;
}

void balloc(int used) {
    uchar buf[BSIZE] = {0};
    printf("balloc: first %d blocks have been allocated\n", used);
    assert(used < BSIZE*8);
    for (int i = 0; i < used; i++) {
        buf[i/8] |= (0x1 << (i%8));
    }
    printf("balloc: write bitmap block at sector %d\n", sb.bmapstart);
    wsect(sb.bmapstart, buf);
}

#define min(a, b) ((a) < (b) ? (a) : (b))

void iappend(uint inum, void *xp, int n) {
    char *p = (char*)xp;
    uint off, fbn, n1;
    struct dinode din;
    char buf[BSIZE];
    uint indirect[NINDIRECT];
    uint x;

    rinode(inum, &din);
    off = xint(din.size);
    while (n > 0) {
        fbn = off / BSIZE;
        assert(fbn < MAXFILE);
        if (fbn < NDIRECT) {
            if (xint(din.addrs[fbn]) == 0) {
                din.addrs[fbn] = xint(freeblock++);
            }
            x = xint(din.addrs[fbn]);
        } else {
            if (xint(din.addrs[NDIRECT]) == 0) {
                din.addrs[NDIRECT] = xint(freeblock++);
            }
            rsect(xint(din.addrs[NDIRECT]), (char*)indirect);
            if (indirect[fbn - NDIRECT] == 0) {
                indirect[fbn - NDIRECT] = xint(freeblock++);
                wsect(xint(din.addrs[NDIRECT]), (char*)indirect);
            }
            x = xint(indirect[fbn-NDIRECT]);
        }
        n1 = min(n, (fbn + 1) * BSIZE - off);
        rsect(x, buf);
        memmove(buf + off - (fbn * BSIZE), p, n1);
        wsect(x, buf);
        n -= n1;
        off += n1;
        p += n1;
    }
    din.size = xint(off);
    winode(inum, &din);
}

void die(const char *s) {
    perror(s);
    exit(1);
}

